import React, { useEffect, useState } from 'react';
import API from '../api/axios';

function HomePage() {
  const [posts, setPosts] = useState([]);
  const [loading, setLoading] = useState(true);

  // 1. Kunin ang data mula sa Backend
  useEffect(() => {
    const fetchPosts = async () => {
      try {
        const { data } = await API.get('/posts');
        setPosts(data);
      } catch (err) {
        console.error("Error fetching posts:", err);
      } finally {
        setLoading(false);
      }
    };
    fetchPosts();
  }, []);

  // Base URL para sa images (Siguraduhing tumutugma sa backend port mo)
  const IMG_URL = 'http://localhost:5000/uploads/';

  return (
    <main>
      <section className="hero">
        <h1>The Purr</h1>
        <p>It isn't merely a sound—it’s a low-frequency engine of contentment...</p>
        <br />
        <img src="/photos/c1.jpg" width="350" height="350" alt="Cead" />
      </section>

      <section className="preview-grid" style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(250px, 1fr))', gap: '20px', padding: '20px' }}>
        {loading ? (
          <p>Loading amazing stories...</p>
        ) : (
          posts.map((post) => (
            <div className="card one" key={post._id} style={{ border: '1px solid #ddd', padding: '15px', borderRadius: '10px' }}>
              <h3>{post.title}</h3>
              <p style={{ fontSize: '0.9rem', color: '#555' }}>
                {post.body.substring(0, 100)}...
              </p>
              <br />
              
              {/* 2. Display ang Uploaded Image */}
              {post.image ? (
                <img 
                  src={`${IMG_URL}${post.image}`} 
                  width="250" 
                  height="250" 
                  alt={post.title} 
                  style={{ objectFit: 'cover', borderRadius: '5px' }}
                />
              ) : (
                <img src="/photos/default.jpg" width="250" height="250" alt="Default" />
              )}

              {/* Opsyonal: Author info */}
              <div style={{ marginTop: '10px', fontSize: '0.8rem', fontWeight: 'bold' }}>
                By: {post.author?.name || 'Anonymous'}
              </div>
            </div>
          ))
        )}
      </section>

      <footer>
        <p>&copy; MiIlao. All rights reserved. | Contact: MiIlao@gmail.com</p>
      </footer>
    </main>
  );
}

export default HomePage;
